def clean_metadata(raw_data):
    key_mapping = {
        "prod_id": "id",
        "val": "price",
        "loc": "region",
        "status": "active"
    }

    def normalize_record(record):
        for key, new_key in key_mapping.items():
            if key in record:
                val = record[key]
                if new_key == "id":
                    record[new_key] = val  # assuming 'id' keys contain numbers
                elif new_key == "active":
                    record[new_key] = True
                else:
                    record[new_key] = float(val) if "." in val else int(val)

    normalized_data = [normalize_record(d.copy()) for d in raw_data]
    return normalized_data

